<script>
export default {
  name: 'BackgroundPage',
  data() {
    // 生成1-12的图片数据
    const galleryImages = [];
    for (let i = 1; i <= 12; i++) {
      const img = require(`@/assets/backgroundpage/${i}.jpg`);
      galleryImages.push({
        src: img,
        realSrc: img, // 暂时使用相同的图片，如果需要悬停切换效果可以配置不同的图片
        caption: '增城榄雕精品作品',
        tag: '榄雕作品',
        isHovered: false
      });
    }

    return {
      features: ['精致小巧', '工艺复杂', '岭南特色', '文化底蕴深厚'],
      // 图库数据
      galleryImages,
      activeSlide: 0,
      slideOffset: 0,
      // 触摸/鼠标滑动
      dragStartX: 0,
      isDragging: false,
      dragDelta: 0,
      // 灯箱
      lightboxVisible: false,
      lightboxIndex: 0,
      showMoreInfo: false,
      zlsImg: require('@/assets/imgs/zls.png'),
      journey: [
        { year: '初中', event: '辍学学习榄雕' },
        { year: '青年', event: '成为职业榄雕师' },
        { year: '中年', event: '开设工作室' },
        { year: '现在', event: ' 非遗传承人' }
      ],
      expanded: {
        inheritor: false,
        student: false
      },
      quizOptions: [
        { text: '核桃', correct: false },
        { text: '桃核', correct: false },
        { text: '古树乌榄核', correct: true },
        { text: '不清楚', correct: false }
      ],
      selectedOption: null,
      showAnswer: false,
      isCorrect: false
    }
  },
  computed: {
    trackStyle() {
      const slideWidth = 220 // px: 208px slide + 12px gap
      const base = -this.activeSlide * slideWidth
      return {
        transform: `translateX(${base + this.dragDelta}px)`,
        transition: this.isDragging ? 'none' : 'transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94)'
      }
    }
  },
  methods: {
    // 触摸事件
    onTouchStart(e) {
      this.dragStartX = e.touches[0].clientX
      this.isDragging = true
      this.dragDelta = 0
    },
    onTouchMove(e) {
      if (!this.isDragging) return
      this.dragDelta = e.touches[0].clientX - this.dragStartX
    },
    onTouchEnd() {
      this.finishDrag()
    },
    // 鼠标拖拽事件
    onMouseDown(e) {
      this.dragStartX = e.clientX
      this.isDragging = true
      this.dragDelta = 0
    },
    onMouseMove(e) {
      if (!this.isDragging) return
      this.dragDelta = e.clientX - this.dragStartX
    },
    onMouseUp() {
      if (!this.isDragging) return
      this.finishDrag()
    },
    finishDrag() {
      const threshold = 50
      if (this.dragDelta < -threshold && this.activeSlide < this.galleryImages.length - 1) {
        this.activeSlide++
      } else if (this.dragDelta > threshold && this.activeSlide > 0) {
        this.activeSlide--
      }
      this.isDragging = false
      this.dragDelta = 0
    },
    goToSlide(index) {
      this.activeSlide = index
    },
    // 灯箱
    openLightbox(index) {
      this.lightboxIndex = index
      this.lightboxVisible = true
    },
    closeLightbox() {
      this.lightboxVisible = false
    },
    lightboxPrev() {
      if (this.lightboxIndex > 0) this.lightboxIndex--
    },
    lightboxNext() {
      if (this.lightboxIndex < this.galleryImages.length - 1) this.lightboxIndex++
    },
    selectOption(index, correct) {
      if (this.showAnswer) return
      this.selectedOption = index
      this.isCorrect = correct
      this.showAnswer = true
    },
    toggleStory(type) {
      this.expanded[type] = !this.expanded[type];
    },
    nextPage() {
      this.$router.push('/data-visualization')
    }
  }
}
</script>

